SELECT count(*) FROM kind_type, title, movie_keyword, cast_info, name, role_type, movie_info, keyword, aka_name WHERE title.kind_id = kind_type.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND movie_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND aka_name.person_id = name.id;